-- =====================================================
-- Phase 1: Multi-Team Support Migration
-- 多部门工艺流程支持数据库迁移
-- =====================================================
-- 1. 新增 DSP 和 SP&I 团队到 organization_units
-- 注意：假设 MFG8 的 id=1，USP 的 id=2
INSERT INTO organization_units (
        parent_id,
        unit_type,
        unit_code,
        unit_name,
        sort_order,
        is_active,
        metadata
    )
VALUES (
        1,
        'TEAM',
        'DSP',
        'DSP',
        1,
        1,
        '{"autoGenerated": false}'
    ),
    (
        1,
        'TEAM',
        'SPI',
        'SP&I',
        2,
        1,
        '{"autoGenerated": false}'
    );
-- 2. 创建操作类型配置表
CREATE TABLE IF NOT EXISTS operation_types (
    id INT PRIMARY KEY AUTO_INCREMENT,
    type_code VARCHAR(20) NOT NULL UNIQUE,
    type_name VARCHAR(50) NOT NULL,
    team_id INT NOT NULL,
    color VARCHAR(7) DEFAULT '#1890ff',
    display_order INT DEFAULT 0,
    is_active BOOLEAN DEFAULT TRUE,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    FOREIGN KEY (team_id) REFERENCES organization_units(id)
);
-- 3. 插入 USP 上游操作类型
INSERT INTO operation_types (
        type_code,
        type_name,
        team_id,
        color,
        display_order
    )
SELECT type_code,
    type_name,
    ou.id,
    color,
    display_order
FROM (
        SELECT 'CELL_THAW' as type_code,
            '细胞复苏' as type_name,
            '#52c41a' as color,
            1 as display_order
        UNION ALL
        SELECT 'CELL_EXPAND',
