            '#1890ff',
            4
        UNION ALL
        SELECT 'INOCULATION',
            '接种',
            '#40a9ff',
            5
        UNION ALL
        SELECT 'CELL_CULTURE',
            '细胞培养',
            '#69c0ff',
            6
        UNION ALL
        SELECT 'FEEDING',
            '补料',
            '#91d5ff',
            7
        UNION ALL
