-- 6. 为 process_templates 添加 team_id 外键
ALTER TABLE process_templates
ADD COLUMN team_id INT NULL
AFTER template_name;
ALTER TABLE process_templates
ADD INDEX idx_team (team_id);
ALTER TABLE process_templates
ADD CONSTRAINT fk_template_team FOREIGN KEY (team_id) REFERENCES organization_units(id);
-- 7. 为 operations 添加 operation_type_id 外键
ALTER TABLE operations
ADD COLUMN operation_type_id INT NULL
AFTER operation_type;
ALTER TABLE operations
ADD CONSTRAINT fk_operation_type FOREIGN KEY (operation_type_id) REFERENCES operation_types(id);
-- 8. 迁移现有模板归属
UPDATE process_templates pt
SET team_id = (
        SELECT id
        FROM organization_units
        WHERE unit_code = 'USP'
    )
WHERE template_name IN ('WBP2486/B', 'WBP2486/B - backup', '长白夜班');
UPDATE process_templates pt
SET team_id = (
        SELECT id
        FROM organization_units
        WHERE unit_code = 'DSP'
    )
WHERE template_name = '下游';
-- 9. 为未指定的模板设置默认 USP
UPDATE process_templates
SET team_id = (
        SELECT id
        FROM organization_units
        WHERE unit_code = 'USP'
    )
WHERE team_id IS NULL;
-- 10. 迁移现有操作类型（保留原枚举值映射到新类型）
-- PREP -> BIOREACTOR_PREP, PROCESS -> CELL_CULTURE, MONITOR -> MONITORING
UPDATE operations o
    JOIN operation_types ot ON ot.type_code = CASE
        WHEN o.operation_type = 'PREP' THEN 'BIOREACTOR_PREP'
        WHEN o.operation_type = 'PROCESS' THEN 'CELL_CULTURE'
        WHEN o.operation_type = 'MONITOR' THEN 'MONITORING'
        ELSE 'CELL_CULTURE'
    END
    JOIN organization_units ou ON ot.team_id = ou.id
    AND ou.unit_code = 'USP'
SET o.operation_type_id = ot.id
WHERE o.operation_type_id IS NULL;